"use strict";(self.webpackChunkdisc_documentation=self.webpackChunkdisc_documentation||[]).push([[5789],{6738:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/NewTrierTownship-FoodPantry-Documentation/","docId":"intro","unlisted":false},{"type":"link","label":"Getting Started","href":"/NewTrierTownship-FoodPantry-Documentation/getting-started","docId":"getting-started","unlisted":false},{"type":"link","label":"Authentication","href":"/NewTrierTownship-FoodPantry-Documentation/authentication","docId":"authentication","unlisted":false},{"type":"category","label":"Frontend","items":[{"type":"link","label":"Project Structure","href":"/NewTrierTownship-FoodPantry-Documentation/frontend/project-structure","docId":"frontend/project-structure","unlisted":false},{"type":"link","label":"Features","href":"/NewTrierTownship-FoodPantry-Documentation/frontend/features","docId":"frontend/features","unlisted":false},{"type":"link","label":"Deployment","href":"/NewTrierTownship-FoodPantry-Documentation/frontend/deployment","docId":"frontend/deployment","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Backend","items":[{"type":"link","label":"Project Structure","href":"/NewTrierTownship-FoodPantry-Documentation/backend/project-structure","docId":"backend/project-structure","unlisted":false},{"type":"link","label":"Architecture & Core Logic","href":"/NewTrierTownship-FoodPantry-Documentation/backend/architecture","docId":"backend/architecture","unlisted":false},{"type":"link","label":"Deployment","href":"/NewTrierTownship-FoodPantry-Documentation/backend/deployment","docId":"backend/deployment","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","label":"Database Schema","href":"/NewTrierTownship-FoodPantry-Documentation/database-schema","docId":"database-schema","unlisted":false},{"type":"link","label":"Known Behaviors","href":"/NewTrierTownship-FoodPantry-Documentation/gotchas","docId":"gotchas","unlisted":false}]},"docs":{"authentication":{"id":"authentication","title":"Authentication","description":"Identity runs on Firebase Auth. The frontend signs users in with Firebase and src/firebase-config.js exports auth and googleProvider. There are three kinds of access: owner, volunteer, and public. Owner and volunteer carry a Firebase token. Public requests carry no token. See Getting Started for the Firebase environment variables.","sidebar":"tutorialSidebar"},"backend/architecture":{"id":"backend/architecture","title":"Architecture & Core Logic","description":"This page lists every HTTP endpoint and describes the core request flows. It pairs with three other pages. For where each file lives and how the app is wired, see Project Structure. For tables, columns, indexes, and constraints, see Database Schema. For how tokens and owner gating work, see Authentication.","sidebar":"tutorialSidebar"},"backend/deployment":{"id":"backend/deployment","title":"Deployment","description":"The backend deploys as a single Firebase Cloud Function (gen 2). The function wraps the Express app and serves every backend route. To run the backend locally, see Getting Started. For how the Express app and the function entry point are split, see Project Structure.","sidebar":"tutorialSidebar"},"backend/project-structure":{"id":"backend/project-structure","title":"Project Structure","description":"The backend is an Express 5 app written in ES modules. It is deployed as a single Firebase Cloud Function that serves every route. For how the function is built and shipped, see Deployment. For the endpoint table and the core request logic, see Architecture & Core Logic.","sidebar":"tutorialSidebar"},"database-schema":{"id":"database-schema","title":"Database Schema","description":"The canonical schema is sql/schema.sql in the backend. It is one file for a fresh database. Run it once against an empty Postgres database and it reproduces the live schema. The database runs on Postgres on Supabase.","sidebar":"tutorialSidebar"},"frontend/deployment":{"id":"frontend/deployment","title":"Deployment","description":"The frontend is a Vite build hosted on Firebase Hosting. Every push to main triggers a GitHub Actions workflow that builds the app and deploys the hosting site. The Cloud Function that serves the API is deployed from the backend repo, not here.","sidebar":"tutorialSidebar"},"frontend/features":{"id":"frontend/features","title":"Features","description":"This page walks through each page and component in the frontend. For each one it","sidebar":"tutorialSidebar"},"frontend/project-structure":{"id":"frontend/project-structure","title":"Project Structure","description":"The frontend is a React 19 app built with Vite. It uses styled-components for styling, Firebase Auth for sign-in, and talks to the backend over HTTP. For what each page does, see Features. For how the app is hosted, see Deployment. For the role model behind the route guards, see Authentication.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"The system is split across two repositories. js-frontend is the React app built with Vite, and js-backend is the Express API. Behind them sit a Supabase Postgres database for data and Firebase for authentication, hosting, and Cloud Functions.","sidebar":"tutorialSidebar"},"gotchas":{"id":"gotchas","title":"Known Behaviors","description":"This page lists behaviors that are correct and intended in the code but are not obvious from the outside. A new developer could read these as bugs. They are not. Each entry says what happens, why, and where the code lives.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"This site documents the New Trier Township Food Pantry inventory system: what it does, how to run it, and how it is built. The stated goal of the project is to replace the pantry\'s spreadsheet-based process with a web app that tracks stock as it moves.","sidebar":"tutorialSidebar"}}}}')}}]);